The following Hemlock program has bugs related to Hemlock's type system, division semantics, and incorrect API usage. Fix all bugs so it produces the expected output.

Remember: In Hemlock, `/` ALWAYS returns a float. Use `divi()` for integer division. Hemlock has no `len()` function — use `.length` property instead.

```hemlock
// Calculate average grade (should be integer: 85)
fn average_grade(grades) {
    let sum = 0;
    for (g in grades) {
        sum += g;
    }
    return sum / len(grades);
}

// Integer division for splitting items into groups
fn split_groups(total, group_size) {
    let full_groups = total / group_size;
    let remainder = total % group_size;
    return { groups: full_groups, leftover: remainder };
}

// Page calculation
fn total_pages(items, per_page) {
    let pages = items / per_page;
    if (items % per_page > 0) {
        pages = pages + 1;
    }
    return pages;
}

let grades = [90, 85, 80, 92, 78];
print("average: " + average_grade(grades));

let result = split_groups(17, 5);
print("groups: " + result.groups + ", leftover: " + result.leftover);

print("pages: " + total_pages(23, 10));
```

